import React from "react";
import 'animate.css/animate.css'
import './index.css';

const Projects = (props) => {
  return(
    <div>
    <hr />
      <div class ="topProj">
        <h2>{props.title}</h2>
        <hr />
        <img src= {props.image} alt ="project image" rounded/>
        <a href ={props.link1}><button
            type="button"
            class="animate__animated animate__zoomIn"
        > View code</button></a>
        <a href ={props.link2}><button
            type="button"
            class="animate__animated animate__zoomIn"
        > View live</button></a>
      </div>
        <p>{props.desc}</p>
        <hr />
    </div>
  );
};
export default Projects;
